INSERT INTO `modulos` VALUES (1,1,'Python M1: Introducción','Conceptos básicos y sintaxis.'),(2,1,'Python M2: Estructuras de Control','Condicionales y ciclos repetitivos.'),(3,1,'Python M3: Funciones','Estructuración y modularidad de código.'),(4,1,'Python M4: Colecciones','Listas, tuplas y diccionarios.'),(5,1,'Python M5: Introducción a Pandas','Uso y manejo de DataFrames.'),(6,1,'Python M6: Limpieza de Datos','Manejo de valores nulos y duplicados.'),(7,1,'Python M7: Visualización Básica','Graficación con Matplotlib y Seaborn.'),(8,1,'Python M8: Proyecto Final Python','Analítica de datos aplicada a un caso real.'),(9,2,'PowerBI M1: Introducción al BI','Conceptos de inteligencia de negocios.'),(10,2,'PowerBI M2: Extracción Power Query','Procesos ETL y limpieza de datos.'),(11,2,'PowerBI M3: Modelado de Datos','Relaciones de esquemas en estrella.'),(12,2,'PowerBI M4: DAX Básico','Creación de medidas y columnas calculadas simples.'),(13,2,'PowerBI M5: DAX Avanzado','Funciones de Time Intelligence y contextos de filtro.'),(14,2,'PowerBI M6: Diseño de Reportes','Principios de UI/UX y storytelling de datos.'),(15,2,'PowerBI M7: Distribución','Publicación en Power BI Service y roles RLS.'),(16,2,'PowerBI M8: Proyecto Final PBI','Desarrollo de un tablero directivo integral.');
/*!40000 ALTER TABLE `modulos` ENABLE KEYS */;
