--
-- Table structure for table `progreso`
--

DROP TABLE IF EXISTS `progreso`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `progreso` (
  `id_progreso` int NOT NULL AUTO_INCREMENT,
  `id_inscripcion` int NOT NULL,
  `id_modulo` int NOT NULL,
  `porcentaje_progreso` decimal(5,2) DEFAULT '0.00',
  `estado` enum('No iniciado','En curso','Completado') DEFAULT 'No iniciado',
  `fecha_actualizacion` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id_progreso`),
  KEY `fk_progreso_inscripciones` (`id_inscripcion`),
  KEY `fk_progreso_modulos` (`id_modulo`),
  CONSTRAINT `fk_progreso_inscripciones` FOREIGN KEY (`id_inscripcion`) REFERENCES `inscripciones` (`id_inscripcion`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_progreso_modulos` FOREIGN KEY (`id_modulo`) REFERENCES `modulos` (`id_modulo`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `chk_porcentaje` CHECK ((`porcentaje_progreso` between 0.00 and 100.00))
) ENGINE=InnoDB AUTO_INCREMENT=24001 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

